//! Parity tables against the pinned Reference
//! (`3b1b/manim @ 6199a00d4c1b1127ebe45cb629c3f22538b10e13`).
//!
//! Fixtures are generated by `scripts/gen_reference_fixtures.py`; regenerate
//! there, never hand-edit. Tolerance is 1e-12 absolute: the formulas agree
//! to ~1e-15, and the slack only absorbs libm ulp differences between
//! platforms (the very differences fmn-dmath will erase for render math).

use fmn_core::color::{Srgb, average_color, color_gradient, interpolate_color};
use fmn_core::constants::*;
use fmn_core::rate;

const TOL: f64 = 1e-12;

fn fixture(name: &str) -> &'static str {
    match name {
        "constants" => include_str!("../fixtures/constants.txt"),
        "rate_manifest" => include_str!("../fixtures/rate_functions.txt"),
        "color_ops" => include_str!("../fixtures/color_ops.txt"),
        _ => unreachable!(),
    }
}

fn assert_close(name: &str, got: f64, want: f64) {
    assert!(
        (got - want).abs() <= TOL,
        "{name}: got {got:?}, Reference says {want:?} (|Δ| = {:e})",
        (got - want).abs()
    );
}

