#[test]
fn constants_match_the_reference() {
    let mut checked = 0usize;
    for line in fixture("constants").lines() {
        if line.starts_with('#') || line.is_empty() {
            continue;
        }
        let mut parts = line.split('\t');
        let name = parts.next().unwrap();
        let fields: Vec<&str> = parts.collect();
        let expect = constant_by_name(name)
            .unwrap_or_else(|| panic!("fixture constant {name} not implemented in fmn-core"));
        match expect {
            Expect::F(got) => {
                assert_eq!(fields.len(), 1, "{name}: field count");
                // Constants are exact: bit-for-bit equal, not merely close.
                assert_eq!(
                    got,
                    fields[0].parse::<f64>().unwrap(),
                    "{name} diverges from the Reference"
                );
            }
            Expect::V(got) => {
                assert_eq!(fields.len(), 3, "{name}: field count");
                for (axis, (g, w)) in got.iter().zip(&fields).enumerate() {
                    assert_eq!(
                        *g,
                        w.parse::<f64>().unwrap(),
                        "{name}[{axis}] diverges from the Reference"
                    );
                }
            }
            Expect::Res((w, h)) => {
                assert_eq!(fields.len(), 2, "{name}: field count");
                assert_eq!(w, fields[0].parse::<u32>().unwrap(), "{name} width");
                assert_eq!(h, fields[1].parse::<u32>().unwrap(), "{name} height");
            }
            Expect::Color(got) => {
                assert_eq!(fields.len(), 1, "{name}: field count");
                let want = Srgb::from_hex(fields[0]).unwrap();
                assert_eq!(got, want, "{name} diverges from the Reference palette");
            }
        }
        checked += 1;
    }
    assert!(
        checked >= 113,
        "expected the full constants table, saw {checked}"
    );
}

// --- rate functions -------------------------------------------------------

#[test]
fn rate_functions_match_the_reference_at_1e4_samples() {
    let bin: &[u8] = include_bytes!("../fixtures/rate_functions.bin");
    let mut offset = 0usize;
    let mut functions_checked = 0usize;
    for line in fixture("rate_manifest").lines() {
        if line.starts_with('#') || line.is_empty() {
            continue;
        }
        let (name, count) = line.split_once('\t').unwrap();
        let count: usize = count.parse().unwrap();
        let n = count - 1;
        let f: Box<dyn Fn(f64) -> f64> = match name {
            "linear" => Box::new(rate::linear),
            "smooth" => Box::new(rate::smooth),
            "rush_into" => Box::new(rate::rush_into),
            "rush_from" => Box::new(rate::rush_from),
            "slow_into" => Box::new(rate::slow_into),
            "double_smooth" => Box::new(rate::double_smooth),
            "there_and_back" => Box::new(rate::there_and_back),
            "there_and_back_with_pause" => {
                Box::new(|t| rate::there_and_back_with_pause(t, 1.0 / 3.0))
            }
            "running_start" => Box::new(|t| rate::running_start(t, -0.5)),
            "overshoot" => Box::new(|t| rate::overshoot(t, 1.5)),
            "wiggle" => Box::new(|t| rate::wiggle(t, 2.0)),
            "lingering" => Box::new(rate::lingering),
            "exponential_decay" => Box::new(|t| rate::exponential_decay(t, 0.1)),
            "not_quite_there_smooth_0.7" => Box::new(rate::not_quite_there(rate::smooth, 0.7)),
            "squish_smooth_0.4_0.6" => Box::new(rate::squish_rate_func(rate::smooth, 0.4, 0.6)),
            other => panic!("fixture rate function {other} not implemented"),
        };
        for i in 0..count {
            let bytes: [u8; 8] = bin[offset + i * 8..offset + i * 8 + 8].try_into().unwrap();
            let want = f64::from_le_bytes(bytes);
            let t = i as f64 / n as f64;
            assert_close(&format!("{name}(t={t})"), f(t), want);
        }
        offset += count * 8;
        functions_checked += 1;
    }
    assert_eq!(functions_checked, 15, "expected the full rate catalog");
    assert_eq!(offset, bin.len(), "fixture and manifest disagree on length");
}

// --- color operations -----------------------------------------------------

#[test]
fn color_operations_match_the_reference() {
    let mut interp = 0usize;
    let mut avg = 0usize;
    let mut grad = 0usize;
    let gradient = color_gradient(&COLORMAP_3B1B, 9);
    for line in fixture("color_ops").lines() {
        if line.starts_with('#') || line.is_empty() {
            continue;
        }
        let fields: Vec<&str> = line.split('\t').collect();
        match fields[0] {
            "interp" => {
                let c1 = palette_by_lower_name(fields[1]);
                let c2 = palette_by_lower_name(fields[2]);
                let alpha: f64 = fields[3].parse().unwrap();
                let got = interpolate_color(c1, c2, alpha);
                for (axis, (g, w)) in [got.r, got.g, got.b].iter().zip(&fields[4..]).enumerate() {
                    assert_close(
                        &format!("interp({}, {}, {alpha})[{axis}]", fields[1], fields[2]),
                        *g,
                        w.parse().unwrap(),
                    );
                }
                interp += 1;
            }
            "average" => {
                let colors: Vec<Srgb> = match fields[1] {
                    "ALL" => ALL_PALETTE.to_vec(),
                    fam => ALL_PALETTE_NAMES
                        .iter()
                        .zip(ALL_PALETTE.iter())
                        .filter(|(n, _)| n.starts_with(&format!("{fam}_")))
                        .map(|(_, c)| *c)
                        .collect(),
                };
                let got = average_color(&colors);
                for (axis, (g, w)) in [got.r, got.g, got.b].iter().zip(&fields[2..]).enumerate() {
                    assert_close(
                        &format!("average({})[{axis}]", fields[1]),
                        *g,
                        w.parse().unwrap(),
                    );
                }
                avg += 1;
            }
            "gradient3b1b" => {
                let j: usize = fields[1].parse().unwrap();
                let got = gradient[j];
                for (axis, (g, w)) in [got.r, got.g, got.b].iter().zip(&fields[2..]).enumerate() {
                    assert_close(
                        &format!("gradient3b1b[{j}][{axis}]"),
                        *g,
                        w.parse().unwrap(),
                    );
                }
                grad += 1;
            }
            other => panic!("unknown color fixture kind {other}"),
        }
    }
    assert!(
        interp >= 300 && avg == 10 && grad == 9,
        "fixture coverage shrank"
    );
}

